'use client'

import { useEffect } from 'react'
import { useAppStore } from '@/lib/store'
import { Activity, Zap, AlertCircle } from 'lucide-react'
import { Badge } from '@/components/ui/badge'

export function ActiveModelsStatus() {
  const { providers, activeBackendModels, fetchActiveModels } = useAppStore()
  
  useEffect(() => {
    fetchActiveModels()
  }, [fetchActiveModels])

  const enabledModelsCount = providers.reduce(
    (count, provider) => count + provider.models.filter((m) => m.enabled).length,
    0
  )

  const hasActiveModels = enabledModelsCount > 0
  const backendConnected = activeBackendModels.length > 0

  return (
    <div className="flex items-center gap-4">
      {/* Backend Status */}
      <div className="flex items-center gap-2">
        <div className={`w-3 h-3 rounded-full ${backendConnected ? 'bg-green-500' : 'bg-red-500'} animate-pulse`} />
        <span className="text-sm text-muted-foreground">
          {backendConnected ? 'Backend Online' : 'Backend Offline'}
        </span>
      </div>

      {/* Active Models Count */}
      {hasActiveModels && (
        <Badge variant="secondary" className="flex items-center gap-2">
          <Zap className="w-3 h-3" />
          {enabledModelsCount} modelo{enabledModelsCount !== 1 ? 's' : ''} ativo{enabledModelsCount !== 1 ? 's' : ''}
        </Badge>
      )}

      {/* Providers Status */}
      <div className="flex items-center gap-2">
        <Activity className="w-4 h-4 text-muted-foreground" />
        <span className="text-sm text-muted-foreground">
          {providers.length} empresa{providers.length !== 1 ? 's' : ''} configurada{providers.length !== 1 ? 's' : ''}
        </span>
      </div>

      {/* Warning if no models selected */}
      {!hasActiveModels && providers.length > 0 && (
        <Badge variant="outline" className="flex items-center gap-2 text-amber-600 border-amber-200">
          <AlertCircle className="w-3 h-3" />
          Selecione modelos
        </Badge>
      )}
    </div>
  )
}
